#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=3e5+5,MAXM=1e6+5;
int n,k,h[MAXN],cnt[MAXM],maxx,ans[MAXM];
int main(void)
{
    // freopen("Spiderman.txt","r",stdin);
    // freopen("Spiderman.txt","w",stdout);
    n=read(),k=read();
    FOR(i,1,n)
    {
        h[i]=read();
        maxx=max(maxx,h[i]);
        ++cnt[h[i]];
    }
    FOR(i,k+1,maxx)
    {
        if(!cnt[i])continue;
        int t=k;
        wh(t<=maxx)
        {
            if(cnt[t])
            {
                ans[t]+=cnt[i];
            }
            t+=i;
        }
    }
    FOR(i,1,n)
    {
        write(ans[h[i]]-(!k));
        putchar(' ');
    }
    return false;
}
